// src/components/Navbar.jsx
import { useState, useEffect } from 'react';
import { personal } from '../data/portfolio';

const links = [
  { href: '#about',      label: 'Sobre mí'   },
  { href: '#experience', label: 'Trayectoria' },
  { href: '#projects',   label: 'Proyectos'  },
  { href: '#contact',    label: 'Contacto'   },
];

export default function Navbar() {
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener('scroll', onScroll);
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  return (
    <nav style={{ ...s.nav, ...(scrolled ? s.navScrolled : s.navTop) }}>

      {/* Logo */}
      <a href="#hero" style={s.logo}>
        {personal.initials}<span style={s.logoAccent}>.</span>
      </a>

      {/* Links */}
      <ul style={s.linksList}>
        {links.map(l => (
          <li key={l.href}>
            <a
              href={l.href}
              style={s.link}
              onMouseEnter={e => (e.target.style.color = 'var(--text)')}
              onMouseLeave={e => (e.target.style.color = 'var(--text2)')}
            >
              {l.label}
            </a>
          </li>
        ))}
      </ul>

      {/* CTA */}
      <a
        href={`mailto:${personal.contact.email}`}
        style={s.cta}
        onMouseEnter={e => {
          e.target.style.background = 'var(--accent2)';
          e.target.style.transform = 'translateY(-1px)';
        }}
        onMouseLeave={e => {
          e.target.style.background = 'var(--accent)';
          e.target.style.transform = 'none';
        }}
      >
        Contrátame
      </a>
    </nav>
  );
}

const s = {
  nav: {
    position: 'fixed', top: 0, left: 0, right: 0, zIndex: 100,
    display: 'flex', alignItems: 'center', justifyContent: 'space-between',
    padding: '0 5%', height: 68,
    borderBottom: '1px solid var(--border)',
    transition: 'background 0.3s, backdrop-filter 0.3s',
  },
  navScrolled: {
    background: 'rgba(12,12,14,0.88)',
    backdropFilter: 'blur(20px)',
  },
  navTop: {
    background: 'transparent',
  },
  logo: {
    fontFamily: 'var(--font-head)',
    fontWeight: 800, fontSize: 18,
    letterSpacing: '-0.5px',
    color: 'var(--text)',
    textDecoration: 'none',
  },
  logoAccent: { color: 'var(--accent)' },
  linksList: {
    display: 'flex', gap: 36, listStyle: 'none',
  },
  link: {
    fontSize: 12, fontWeight: 500,
    letterSpacing: '0.1em', textTransform: 'uppercase',
    color: 'var(--text2)',
    textDecoration: 'none',
    transition: 'color 0.2s',
    cursor: 'pointer',
  },
  cta: {
    background: 'var(--accent)',
    color: '#fff', border: 'none',
    padding: '9px 22px', borderRadius: 6,
    fontFamily: 'var(--font-body)',
    fontSize: 13, fontWeight: 500,
    cursor: 'pointer',
    transition: 'background 0.2s, transform 0.15s',
    textDecoration: 'none',
    display: 'inline-block',
  },
};
